import React, { use } from 'react';
import { Navigate } from 'react-router-dom';
import MasterLayout from '../layouts/admin/MasterLayout';
import axios from 'axios';

function AdminPrivateRoute()
{
    const [Authenticated, setAuthenticated] = useState(false);
    useEffect(() => 
    {
        axios.get('/api/checkingAuthenticated').then((response) =>
        {
            if (response.data.authenticated)
            {
                setAuthenticated(true);
            }
        });

        return () =>
        {
            setAuthenticated(false);
        };
    }, []);



    // In react-router-dom v6, a private route component
    // returns the protected component or a <Navigate> element.
    const isAuthenticated = !!localStorage.getItem('auth_token');

    // Using 'replace' is important for login redirects to avoid a broken back button behavior.
    return isAuthenticated ? <MasterLayout /> : <Navigate to="/login" replace />;
}

export default AdminPrivateRoute;
